import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isRegisterMode, setIsRegisterMode] = useState(false); // NUEVO: Para cambiar entre login/registro

  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [nuevoRol, setNuevoRol] = useState('vendedor'); // Nuevo usuario es vendedor por defecto

  const [userRole, setUserRole] = useState('');
  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);

  // ... (manten tus funciones cargarDatos y useEffect igual)

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setIsLoggedIn(true);
        setUserRole(res.data.rol);
      }
    } catch (e) { alert("Usuario o contraseña incorrectos"); }
  };

  const handleRegister = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/register', { 
        usuario: usuario, 
        clave: password, 
        rol: nuevoRol 
      });
      if (res.data.success) {
        alert("¡Usuario registrado! Ahora puedes iniciar sesión.");
        setIsRegisterMode(false); // Volver al login
      }
    } catch (e) { alert("Error al registrar: El usuario ya existe"); }
  };

  // --- VISTA DE LOGIN Y REGISTRO ---
  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="login-card">
          <h2>{isRegisterMode ? 'Crear Cuenta' : 'Iniciar Sesión'}</h2>

          <div className="form-group">
            <label>Usuario:</label>
            <input type="text" placeholder="Ej: eduardo" value={usuario} onChange={(e) => setUsuario(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Contraseña:</label>
            <input type="password" placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} />
          </div>

          {isRegisterMode && (
            <div className="form-group">
              <label>Rol de usuario:</label>
              <select className="select-rol" onChange={(e) => setNuevoRol(e.target.value)}>
                <option value="vendedor">Vendedor</option>
                <option value="admin">Administrador</option>
              </select>
            </div>
          )}

          {isRegisterMode ? (
            <>
              <button className="btn-entrar" onClick={handleRegister}>Registrarme</button>
              <p onClick={() => setIsRegisterMode(false)} style={{cursor:'pointer', color:'#2c97ad', marginTop:'15px'}}>¿Ya tienes cuenta? Inicia sesión</p>
            </>
          ) : (
            <>
              <button className="btn-entrar" onClick={handleLogin}>Entrar</button>
              <button className="btn-registrar" onClick={() => setIsRegisterMode(true)}>Registrarse</button>
            </>
          )}
        </div>
      </div>
    );
  }

  // --- VISTA DASHBOARD (Ajustada para scroll y móvil) ---
  return (
    <div style={{minHeight: '100vh', display: 'flex', flexDirection: 'column'}}>
      <header className="header">
        <h1 style={{fontSize: '18px'}}>Mi Tiendita</h1>
        <button className="btn-cerrar" onClick={() => setIsLoggedIn(false)}>Salir</button>
      </header>

      <nav className="nav-bar">
        <span className="nav-link" onClick={() => setView('dashboard')}>Dashboard</span>
        {userRole === 'admin' && <span className="nav-link" onClick={() => setView('gestion')}>Inventario</span>}
      </nav>

      <main style={{ padding: '15px', flex: 1 }}>
        {view === 'dashboard' ? (
          <div className="dashboard-grid">
            {/* Las tarjetas ahora se acomodan solas en celular */}
            <div className="card">
                <h3>Bajo Stock</h3>
                <div className="card-content">{stats.bajo_stock} productos.</div>
            </div>
            <div className="card">
                <h3>Estadísticas</h3>
                <div className="card-content">
                    <p>Total: {stats.total_productos}</p>
                    <p>Valor: ${stats.valor_inventario}</p>
                </div>
            </div>
          </div>
        ) : (
          <div className="card">
            <h3>Gestión de Inventario</h3>
            {/* Contenedor para que la tabla no rompa el diseño en celular */}
            <div className="table-container">
              <table style={{width:'100%', minWidth: '500px'}}>
                <thead>
                  <tr><th>Producto</th><th>Stock</th><th>Precio</th><th>Acciones</th></tr>
                </thead>
                <tbody>
                  {productos.map(p => (
                    <tr key={p.id} className="table-row">
                      <td style={{padding:'10px'}}>{p.nombre}</td>
                      <td>{p.stock}</td>
                      <td>${p.precio_venta}</td>
                      <td><button>✏️</button></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
